const body = $('Webhook omghat').item.json.body;

const agentName = body.agent_name;
const tone = body.tone;
const prompt = body.prompt;
const faqs = body.faqs || [];
const escalationPhone = body.escalation_phone;
const images = body.images || [];
const documents = body.catalogs || [];

function dividirEnPartes(texto, maxLen) {
  const partes = [];
  let inicio = 0;
  while (inicio < texto.length) {
    let fin = inicio + maxLen;
    if (fin >= texto.length) {
      partes.push(texto.substring(inicio).trim());
      break;
    }
    let corte = texto.lastIndexOf(' ', fin);
    if (corte <= inicio) corte = fin;
    partes.push(texto.substring(inicio, corte).trim());
    inicio = corte + 1;
  }
  return partes.filter(p => p.length > 0);
}

const chunks = [];

const regex = /(\n\s*\d+\.\s+[^\n]+)/g;
const matches = [...prompt.matchAll(regex)];

if (matches.length === 0) {
  const secciones = prompt.split(/\n{2,}/).map(s => s.trim()).filter(s => s.length > 20);
  secciones.forEach((seccion, i) => {
    const partes = dividirEnPartes(seccion, 480);
    partes.forEach((parte, k) => {
      chunks.push({
        id: `contexto_${agentName}_sec${String(i+1).padStart(2,'0')}_${String(k+1).padStart(2,'0')}`,
        tipo: "conocimiento_tecnico",
        contenido: parte,
        metadata: { categoria: "conocimiento_tecnico", relevancia: 1.0, uso: `contexto_seccion_${i+1}` }
      });
    });
  });
} else {
  const indices = matches.map(m => m.index);
  indices.push(prompt.length);

  const intro = prompt.substring(0, indices[0]).trim();
  if (intro.length > 20) {
    dividirEnPartes(intro, 480).forEach((parte, k) => {
      chunks.push({
        id: `contexto_${agentName}_intro_${String(k+1).padStart(2,'0')}`,
        tipo: "conocimiento_tecnico",
        contenido: parte,
        metadata: { categoria: "conocimiento_tecnico", relevancia: 1.0, uso: "contexto_intro" }
      });
    });
  }

  matches.forEach((match, i) => {
    const seccion = prompt.substring(indices[i], indices[i + 1]).trim();
    dividirEnPartes(seccion, 480).forEach((parte, k) => {
      chunks.push({
        id: `contexto_${agentName}_sec${String(i+1).padStart(2,'0')}_${String(k+1).padStart(2,'0')}`,
        tipo: "conocimiento_tecnico",
        contenido: parte,
        metadata: { categoria: "conocimiento_tecnico", relevancia: 1.0, uso: `contexto_seccion_${i+1}` }
      });
    });
  });
}

faqs.forEach((faq, i) => {
  chunks.push({
    id: `faq_${agentName}_${String(i+1).padStart(3,'0')}`,
    tipo: "faq",
    contenido: `PREGUNTA: '${faq.question}'. RESPUESTA: '${faq.answer}'.`,
    metadata: { categoria: "faq", relevancia: 0.9, uso: "faq_general", intencion: "consulta" }
  });
});

chunks.push({
  id: `escalamiento_humano_${agentName}_001`,
  tipo: "procedimiento",
  contenido: `ACCIÓN: Si cliente pide humano, reclama pedido anterior, está listo para pagar, queja repetida o lenguaje ofensivo → responder SOLO [ESCALAR]. Número de escalamiento: ${escalationPhone}. NUNCA ignorar solicitudes de escalamiento.`,
  metadata: { categoria: "procedimiento", relevancia: 0.9, uso: "escalamiento" }
});

images.forEach((img, i) => {
  chunks.push({
    id: `media_imagen_${agentName}_${String(i+1).padStart(3,'0')}`,
    tipo: "media",
    contenido: `IMAGEN: ${img.title}. Mostrar cuando cliente pregunte por ${img.title} o solicite ver alojamiento visualmente. [IMG:${img.url}]`,
    metadata: { categoria: "media", relevancia: 0.9, uso: `visual_${img.title.toLowerCase().replace(/\s+/g,'_')}` }
  });
});

documents.forEach((doc, i) => {
  const fileName = doc.fileName || doc.url.split('/').pop();
  chunks.push({
    id: `media_documento_${agentName}_${String(i+1).padStart(3,'0')}`,
    tipo: "media",
    contenido: `DOCUMENTO: ${doc.title}. Enviar cuando cliente pida ${doc.title} o solicite el catálogo, lista de precios o documentación. [DOC:${doc.url}|${fileName}]`,
    metadata: { categoria: "media", relevancia: 0.9, uso: `documento_${doc.title.toLowerCase().replace(/\s+/g,'_')}` }
  });
});

return chunks.map(chunk => ({
  json: {
    text: chunk.contenido,
    id: chunk.id,
    tipo: chunk.tipo,
    categoria: chunk.metadata.categoria,
    relevancia: chunk.metadata.relevancia,
    uso: chunk.metadata.uso,
    ...(chunk.metadata.intencion ? { intencion: chunk.metadata.intencion } : {})
  }
}));

const prompt = $('Prompts').first().json.output ?? '';                                                                                                                  
  const errores = [];

  // ── SECCIONES OBLIGATORIAS ──
  const secciones = ['ROL', 'PERSONALIDAD', 'REGLAS', 'FAQS', 'FLUJO', 'RECURSOS DISPONIBLES', 'ESCALAMIENTO', 'LÍMITES'];
  for (const seccion of secciones) {
    if (!prompt.includes(seccion))
      errores.push(`FALTA SECCIÓN: ${seccion}`);
  }

  // ── HERRAMIENTAS Y ETIQUETAS ──
  if (!prompt.includes('qdrant_knowledge'))
    errores.push('FALTA: llamada qdrant_knowledge obligatoria');

  if (!prompt.includes('[IMG:'))
    errores.push('FALTA: regla etiqueta imagen [IMG:url]');

  if (!prompt.includes('[DOC:'))
    errores.push('FALTA: regla etiqueta documento [DOC:url|nombre]');

  if (!prompt.includes('[ESCALAR]'))
    errores.push('FALTA: instrucción [ESCALAR]');

  // ── DATOS DEL WEBHOOK ──
  const input = $('Webhook omghat').first().json.body ?? $('Webhook omghat').first().json;

  if (input.agent_name && !prompt.includes(input.agent_name))
    errores.push(`FALTA: nombre del agente "${input.agent_name}" no aparece en el prompt`);

  if (input.escalation_phone && !prompt.includes(input.escalation_phone))
    errores.push('FALTA: teléfono de escalamiento no incluido');

  if (input.admin_phone && !prompt.includes(input.admin_phone))
    errores.push('FALTA: teléfono admin no incluido');

  // Verificar que las FAQs del input estén reflejadas
  if (input.faqs && input.faqs.length > 0) {
    const faqsPresentes = input.faqs.filter(f => prompt.includes(f.question)).length;
    if (faqsPresentes === 0)
      errores.push('FALTA: ninguna FAQ del input aparece en el prompt');
    else if (faqsPresentes < input.faqs.length)
      errores.push(`INCOMPLETO: solo ${faqsPresentes}/${input.faqs.length} FAQs incluidas`);
  }

  // Verificar mención de catálogos si existen
  if (input.catalogs && input.catalogs.length > 0 && !prompt.includes('catálogo') && !prompt.includes('Catálogo'))
    errores.push('FALTA: no menciona catálogos existentes');

  // Verificar mención de imágenes si existen
  if (input.images && input.images.length > 0 && !prompt.includes('imagen') && !prompt.includes('Imagen'))
    errores.push('FALTA: no menciona imágenes existentes');

  // ── TONO ──
  const tonoMap = {
    friendly: ['tutea', 'tú', 'cercano'],
    formal: ['usted', 'profesional'],
    casual: ['relajado', 'emoji'],
    empathetic: ['comprensivo', 'empat'],
    enthusiastic: ['energético', 'entusias', '!'],
  };
  if (input.tone && tonoMap[input.tone]) {
    const palabrasTono = tonoMap[input.tone];
    const tonoPresente = palabrasTono.some(p => prompt.toLowerCase().includes(p.toLowerCase()));
    if (!tonoPresente)
      errores.push(`TONO: no refleja "${input.tone}" — esperaba alguna de: ${palabrasTono.join(', ')}`);
  }

  // ── FORMATO ──
  if (prompt.includes('**') || prompt.includes('## ') || prompt.includes('```'))
    errores.push('CONTIENE: markdown prohibido (**, ## o ```)');

  if (prompt.length > 2200)
    errores.push(`EXCEDE: límite de caracteres (actual: ${prompt.length}, máx: 2200)`);

  if (prompt.length < 400)
    errores.push(`MUY CORTO: prompt sospechosamente corto (${prompt.length} chars)`);

  // ── REGLAS DE COMPORTAMIENTO ──
  if (!prompt.includes('historial') && !prompt.includes('saludo'))
    errores.push('FALTA: regla de saludo condicional según historial');

  if (!prompt.includes('3 líneas') && !prompt.includes('máximo 3'))
    errores.push('FALTA: regla de máximo 3 líneas por respuesta');

  if (!prompt.includes('No escalar') && !prompt.includes('NO escalar'))
    errores.push('FALTA: regla de cuándo NO escalar');
if (!prompt.includes('REGLA 0') && !prompt.includes('output limpio') && !prompt.includes('etiquetas internas'))
  errores.push('FALTA regla de output limpio sin etiquetas internas');

  // ── RESULTADO ──
  return [{
    json: {
      prompt,
      aprobado: errores.length === 0,
      errores,
      errores_count: errores.length,
      chars: prompt.length
    }
  }];

return $('Webhook omghat1').item.json.body.images.map(img => ({
  json: {
    agent_slug: $('Webhook omghat1').item.json.body.agent_slug,
    title: img.title,
    url: img.url
  }
}));

// ============================================================
// CHUNKER SEMÁNTICO MEJORADO - Context Engineering
// Genera chunks tipados con metadata rica para retrieval
// ============================================================

const body = $('Webhook omghat1').item.json.body;
const slug = body.agent_slug;
const agentName = body.agent_name;
const tone = body.tone;
const prompt = body.prompt;
const faqs = body.faqs || [];
const escalationPhone = body.escalation_phone;
const adminPhone = body.admin_phone;
const images = body.images || [];
const catalogs = body.catalogs || [];

function splitText(texto, maxLen) {
  const partes = [];
  let inicio = 0;
  while (inicio < texto.length) {
    let fin = inicio + maxLen;
    if (fin >= texto.length) { partes.push(texto.substring(inicio).trim()); break; }
    let corte = texto.lastIndexOf(' ', fin);
    if (corte <= inicio) corte = fin;
    partes.push(texto.substring(inicio, corte).trim());
    inicio = corte + 1;
  }
  return partes.filter(p => p.length > 0);
}

const chunks = [];

// ── 1. IDENTIDAD ──
chunks.push({
  text: `IDENTIDAD DEL NEGOCIO: ${agentName}. ${prompt.substring(0, 300).replace(/\n/g, ' ')}`,
  id: `identidad_${slug}_001`,
  tipo: 'identidad',
  categoria: 'identidad',
  relevancia: 1.0,
  uso: 'primer_contacto',
  trigger_keywords: 'saludo,hola,buenos dias,quién,qué es,información'
});

// ── 2. PRODUCTOS/SERVICIOS ──
// Detectar bloques de productos por patrones de precio
const precioRegex = /●?\s*([A-ZÁÉÍÓÚa-záéíóúñÑ][A-ZÁÉÍÓÚa-záéíóúñÑ\s]+?)\s*[–—-]\s*\$([0-9.,]+)/g;
let match;
const productos = [];
while ((match = precioRegex.exec(prompt)) !== null) {
  productos.push({ nombre: match[1].trim(), precio: match[2].trim() });
}

// Si detectó productos, crear un chunk por cada uno o agrupados
if (productos.length > 0) {
  // Chunk de resumen de tarifas
  const resumenTarifas = productos.map(p => `${p.nombre}: $${p.precio}`).join('. ');
  chunks.push({
    text: `TARIFAS Y PRECIOS DE ${agentName}: ${resumenTarifas}`,
    id: `producto_tarifas_${slug}_001`,
    tipo: 'producto',
    categoria: 'producto',
    relevancia: 1.0,
    uso: 'consulta_precios',
    trigger_keywords: 'precio,tarifa,cuánto,cuesta,valor,opciones,alojamiento'
  });
}

// ── 3. SECCIONES DEL PROMPT COMO CONOCIMIENTO TÉCNICO ──
// Detectar secciones numeradas del prompt
const seccionRegex = /(?:🟢\s*)?\d+\.\s*([^\n]+)([\s\S]*?)(?=(?:🟢\s*)?\d+\.|$)/g;
let secMatch;
const secciones = [];
while ((secMatch = seccionRegex.exec(prompt)) !== null) {
  secciones.push({
    titulo: secMatch[1].trim(),
    contenido: secMatch[2].trim()
  });
}

if (secciones.length > 0) {
  secciones.forEach((sec, i) => {
    if (sec.contenido.length < 20) return;
    const partes = splitText(sec.contenido, 600);
    partes.forEach((parte, k) => {
      // Detectar tipo por título
      let tipo = 'conocimiento';
      let trigger = '';
      const tituloLower = sec.titulo.toLowerCase();

      if (tituloLower.includes('bienvenida') || tituloLower.includes('inicial')) {
        tipo = 'flujo_bienvenida';
        trigger = 'hola,buenos,primera vez,saludo';
      } else if (tituloLower.includes('ubicac')) {
        tipo = 'ubicacion';
        trigger = 'dónde,ubicación,dirección,cómo llego,mapa';
      } else if (tituloLower.includes('tarifa') || tituloLower.includes('precio')) {
        tipo = 'producto';
        trigger = 'precio,tarifa,cuánto,cuesta,valor';
      } else if (tituloLower.includes('capacidad')) {
        tipo = 'producto';
        trigger = 'capacidad,personas,cuántos,parejas,familiar';
      } else if (tituloLower.includes('reserv')) {
        tipo = 'proceso';
        trigger = 'reservar,apartar,pagar,abono,cuenta';
      } else if (tituloLower.includes('polít')) {
        tipo = 'politica';
        trigger = 'devolución,cancelar,cambio,política';
      } else if (tituloLower.includes('cierre')) {
        tipo = 'flujo_cierre';
        trigger = 'gracias,listo,perfecto,cierre';
      } else if (tituloLower.includes('descuento') || tituloLower.includes('semana')) {
        tipo = 'producto';
        trigger = 'descuento,promoción,entre semana,oferta';
      }

      chunks.push({
        text: `${sec.titulo.toUpperCase()}: ${parte}`,
        id: `conocimiento_${slug}_sec${String(i+1).padStart(2,'0')}_${String(k+1).padStart(2,'0')}`,
        tipo,
        categoria: tipo,
        relevancia: 0.95,
        uso: `seccion_${sec.titulo.toLowerCase().replace(/[^a-z0-9]/g,'_').substring(0,30)}`,
        trigger_keywords: trigger
      });
    });
  });
} else {
  // Fallback: dividir por párrafos
  const parrafos = prompt.split(/\n{2,}/).map(s => s.trim()).filter(s => s.length > 30);
  parrafos.forEach((parr, i) => {
    splitText(parr, 600).forEach((parte, k) => {
      chunks.push({
        text: parte,
        id: `conocimiento_${slug}_p${String(i+1).padStart(2,'0')}_${String(k+1).padStart(2,'0')}`,
        tipo: 'conocimiento',
        categoria: 'conocimiento',
        relevancia: 0.9,
        uso: `parrafo_${i+1}`,
        trigger_keywords: ''
      });
    });
  });
}

// ── 4. FAQs ──
faqs.forEach((faq, i) => {
  if (!faq.question || !faq.answer || faq.answer.length < 3) return;
  chunks.push({
    text: `PREGUNTA FRECUENTE: ${faq.question} RESPUESTA: ${faq.answer}`,
    id: `faq_${slug}_${String(i+1).padStart(3,'0')}`,
    tipo: 'faq',
    categoria: 'faq',
    relevancia: 0.9,
    uso: 'faq_general',
    trigger_keywords: faq.question.toLowerCase().replace(/[¿?]/g, '').substring(0, 60)
  });
});

// ── 5. ESCALAMIENTO ──
chunks.push({
  text: `PROTOCOLO DE ESCALAMIENTO: Responder SOLO [ESCALAR] cuando: cliente confirma intención de pago o reserva, cliente pide hablar con humano, cliente reclama pedido anterior, la base de conocimiento no resuelve tras 1 intento, frustración en 3+ mensajes consecutivos, lenguaje ofensivo por segunda vez. Teléfono escalamiento: ${escalationPhone}. Teléfono admin: ${adminPhone}. NO escalar por: saludos, preguntas de info, precios, catálogo, ubicación, políticas generales.`,
  id: `escalamiento_${slug}_001`,
  tipo: 'procedimiento',
  categoria: 'escalamiento',
  relevancia: 1.0,
  uso: 'escalamiento',
  trigger_keywords: 'humano,persona,queja,reclamo,pagar,reservar,frustrado,enojado'
});

// ── 6. MEDIA - IMÁGENES ──
images.forEach((img, i) => {
  chunks.push({
    text: `IMAGEN DISPONIBLE: ${img.title}. Enviar cuando el cliente pregunte por ${img.title} o quiera ver fotos del alojamiento. Para enviar usa exactamente: [IMG:${img.url}]`,
    id: `media_img_${slug}_${String(i+1).padStart(3,'0')}`,
    tipo: 'media',
    categoria: 'media_imagen',
    relevancia: 0.9,
    uso: `visual_${img.title.toLowerCase().replace(/\s+/g,'_')}`,
    trigger_keywords: `${img.title.toLowerCase()},foto,imagen,ver,mostrar`
  });
});

// ── 7. MEDIA - CATÁLOGOS ──
catalogs.forEach((doc, i) => {
  const fileName = doc.fileName || doc.url.split('/').pop();
  chunks.push({
    text: `DOCUMENTO DISPONIBLE: ${doc.title}. Enviar cuando el cliente pida catálogo, lista de precios o documentación técnica. Para enviar usa exactamente: [DOC:${doc.url}|${fileName}]`,
    id: `media_doc_${slug}_${String(i+1).padStart(3,'0')}`,
    tipo: 'media',
    categoria: 'media_documento',
    relevancia: 0.9,
    uso: `documento_${doc.title.toLowerCase().replace(/\s+/g,'_')}`,
    trigger_keywords: `${doc.title.toLowerCase()},catálogo,documento,pdf,lista,precios`
  });
});

// ── 8. TONO Y PERSONALIDAD ──
const tonoDescripcion = {
  friendly: 'Tutea al cliente, sé cálido, cercano, colombiano natural. Usa emojis con moderación.',
  formal: 'Trata de usted, sé profesional y serio. No uses emojis.',
  casual: 'Sé relajado, usa emojis, lenguaje coloquial colombiano.',
  empathetic: 'Sé comprensivo, valida las emociones del cliente, ten paciencia.',
  enthusiastic: 'Sé energético, usa exclamaciones, motiva al cliente.'
};

chunks.push({
  text: `PERSONALIDAD Y TONO: Tono configurado: ${tone}. ${tonoDescripcion[tone] || tonoDescripcion.friendly}. Español colombiano, buena ortografía. Si no sabes algo responde: déjame verificar eso con mi equipo. Formato: texto plano para WhatsApp, prohibido markdown.`,
  id: `personalidad_${slug}_001`,
  tipo: 'personalidad',
  categoria: 'personalidad',
  relevancia: 1.0,
  uso: 'tono_estilo',
  trigger_keywords: ''
});

return chunks.map(chunk => ({ json: chunk }));

