// Parsear el output del Agente 1 y convertir cada ejemplo en un chunk para Qdrant

const slug = $('Webhook omghat1').item.json.body.agent_slug;
const raw = $('Agente 1 - Few Shot Generator').item.json.output || '';

let ejemplos = [];
try {
  // Limpiar posible markdown
  let clean = raw.replace(/```json/g, '').replace(/```/g, '').trim();
  ejemplos = JSON.parse(clean);
} catch (e) {
  // Intentar extraer JSON del texto
  const jsonMatch = raw.match(/\[\s*\{[\s\S]*\}\s*\]/);
  if (jsonMatch) {
    try {
      ejemplos = JSON.parse(jsonMatch[0]);
    } catch (e2) {
      return [{ json: { text: 'Error parseando ejemplos: ' + e2.message, id: 'error_parse', tipo: 'error', categoria: 'error', relevancia: 0, uso: 'debug', trigger_keywords: '' } }];
    }
  }
}

if (!Array.isArray(ejemplos) || ejemplos.length === 0) {
  return [{ json: { text: 'No se generaron ejemplos', id: 'error_empty', tipo: 'error', categoria: 'error', relevancia: 0, uso: 'debug', trigger_keywords: '' } }];
}

return ejemplos.map((ej, i) => {
  const esTipo = ej.tipo === 'negativo' ? 'ejemplo_negativo' : 'ejemplo_positivo';
  const prefijo = ej.tipo === 'negativo' 
    ? `EJEMPLO DE LO QUE NO DEBES HACER (${ej.escenario}): ` 
    : `EJEMPLO DE CONVERSACIÓN IDEAL (${ej.escenario}): `;

  return {
    json: {
      text: prefijo + ej.conversacion,
      id: `fewshot_${slug}_${String(i+1).padStart(3,'0')}`,
      tipo: esTipo,
      categoria: esTipo,
      relevancia: ej.tipo === 'negativo' ? 0.85 : 0.95,
      uso: `ejemplo_${ej.escenario.toLowerCase().replace(/[^a-z0-9]/g,'_')}`,
      trigger_keywords: ej.trigger_keywords || ej.escenario.toLowerCase()
    }
  };
});

