function dividirEnPartes(texto, maxLen) {
  const partes = [];
  let inicio = 0;
  while (inicio < texto.length) {
    let fin = inicio + maxLen;
    if (fin >= texto.length) {
      partes.push(texto.substring(inicio).trim());
      break;
    }
    let corte = texto.lastIndexOf(' ', fin);
    if (corte <= inicio) corte = fin;
    partes.push(texto.substring(inicio, corte).trim());
    inicio = corte + 1;
  }
  return partes.filter(p => p.length > 0);
}

const chunks = [];

const regex = /(\n\s*\d+\.\s+[^\n]+)/g;
const matches = [...prompt.matchAll(regex)];

if (matches.length === 0) {
  const secciones = prompt.split(/\n{2,}/).map(s => s.trim()).filter(s => s.length > 20);
  secciones.forEach((seccion, i) => {
    const partes = dividirEnPartes(seccion, 480);
    partes.forEach((parte, k) => {
      chunks.push({
        id: `contexto_${agentName}_sec${String(i+1).padStart(2,'0')}_${String(k+1).padStart(2,'0')}`,
        tipo: "conocimiento_tecnico",
        contenido: parte,
        metadata: { categoria: "conocimiento_tecnico", relevancia: 1.0, uso: `contexto_seccion_${i+1}` }
      });
    });
  });
} else {
  const indices = matches.map(m => m.index);
  indices.push(prompt.length);

  const intro = prompt.substring(0, indices[0]).trim();
  if (intro.length > 20) {
    dividirEnPartes(intro, 480).forEach((parte, k) => {
      chunks.push({
        id: `contexto_${agentName}_intro_${String(k+1).padStart(2,'0')}`,
        tipo: "conocimiento_tecnico",
        contenido: parte,
        metadata: { categoria: "conocimiento_tecnico", relevancia: 1.0, uso: "contexto_intro" }
      });
    });
  }

  matches.forEach((match, i) => {
    const seccion = prompt.substring(indices[i], indices[i + 1]).trim();
    dividirEnPartes(seccion, 480).forEach((parte, k) => {
      chunks.push({
        id: `contexto_${agentName}_sec${String(i+1).padStart(2,'0')}_${String(k+1).padStart(2,'0')}`,
        tipo: "conocimiento_tecnico",
        contenido: parte,
        metadata: { categoria: "conocimiento_tecnico", relevancia: 1.0, uso: `contexto_seccion_${i+1}` }
      });
    });
  });
}

faqs.forEach((faq, i) => {
  chunks.push({
    id: `faq_${agentName}_${String(i+1).padStart(3,'0')}`,
    tipo: "faq",
    contenido: `PREGUNTA: '${faq.question}'. RESPUESTA: '${faq.answer}'.`,
    metadata: { categoria: "faq", relevancia: 0.9, uso: "faq_general", intencion: "consulta" }
  });
});

chunks.push({
