const prompt = $('Prompts1').first().json.output ?? '';                                                                                                                  
  const errores = [];

  // ── SECCIONES OBLIGATORIAS ──
  const secciones = ['ROL', 'PERSONALIDAD', 'REGLAS', 'FAQS', 'FLUJO', 'RECURSOS DISPONIBLES', 'ESCALAMIENTO', 'LÍMITES'];
  for (const seccion of secciones) {
    if (!prompt.includes(seccion))
      errores.push(`FALTA SECCIÓN: ${seccion}`);
  }

  // ── HERRAMIENTAS Y ETIQUETAS ──
  if (!prompt.includes('qdrant_knowledge'))
    errores.push('FALTA: llamada qdrant_knowledge obligatoria');

  if (!prompt.includes('[IMG:'))
    errores.push('FALTA: regla etiqueta imagen [IMG:url]');

  if (!prompt.includes('[DOC:'))
    errores.push('FALTA: regla etiqueta documento [DOC:url|nombre]');

  if (!prompt.includes('[ESCALAR]'))
    errores.push('FALTA: instrucción [ESCALAR]');

  // ── DATOS DEL WEBHOOK ──
  const input = $('Webhook omghat2').first().json.body ?? $('Webhook omghat2').first().json;

  if (input.agent_name && !prompt.includes(input.agent_name))
    errores.push(`FALTA: nombre del agente "${input.agent_name}" no aparece en el prompt`);

  if (input.escalation_phone && !prompt.includes(input.escalation_phone))
    errores.push('FALTA: teléfono de escalamiento no incluido');

  if (input.admin_phone && !prompt.includes(input.admin_phone))
    errores.push('FALTA: teléfono admin no incluido');

  // Verificar que las FAQs del input estén reflejadas
  if (input.faqs && input.faqs.length > 0) {
    const faqsPresentes = input.faqs.filter(f => prompt.includes(f.question)).length;
    if (faqsPresentes === 0)
      errores.push('FALTA: ninguna FAQ del input aparece en el prompt');
    else if (faqsPresentes < input.faqs.length)
      errores.push(`INCOMPLETO: solo ${faqsPresentes}/${input.faqs.length} FAQs incluidas`);
  }

  // Verificar mención de catálogos si existen
  if (input.catalogs && input.catalogs.length > 0 && !prompt.includes('catálogo') && !prompt.includes('Catálogo'))
    errores.push('FALTA: no menciona catálogos existentes');

  // Verificar mención de imágenes si existen
  if (input.images && input.images.length > 0 && !prompt.includes('imagen') && !prompt.includes('Imagen'))
    errores.push('FALTA: no menciona imágenes existentes');

  // ── TONO ──
  const tonoMap = {
    friendly: ['tutea', 'tú', 'cercano'],
    formal: ['usted', 'profesional'],
    casual: ['relajado', 'emoji'],
    empathetic: ['comprensivo', 'empat'],
    enthusiastic: ['energético', 'entusias', '!'],
  };
  if (input.tone && tonoMap[input.tone]) {
    const palabrasTono = tonoMap[input.tone];
    const tonoPresente = palabrasTono.some(p => prompt.toLowerCase().includes(p.toLowerCase()));
    if (!tonoPresente)
      errores.push(`TONO: no refleja "${input.tone}" — esperaba alguna de: ${palabrasTono.join(', ')}`);
  }

  // ── FORMATO ──
  if (prompt.includes('**') || prompt.includes('## ') || prompt.includes('```'))
    errores.push('CONTIENE: markdown prohibido (**, ## o ```)');

  if (prompt.length > 2200)
    errores.push(`EXCEDE: límite de caracteres (actual: ${prompt.length}, máx: 2200)`);

  if (prompt.length < 400)
    errores.push(`MUY CORTO: prompt sospechosamente corto (${prompt.length} chars)`);

  // ── REGLAS DE COMPORTAMIENTO ──
  if (!prompt.includes('historial') && !prompt.includes('saludo'))
    errores.push('FALTA: regla de saludo condicional según historial');

  if (!prompt.includes('3 líneas') && !prompt.includes('máximo 3'))
    errores.push('FALTA: regla de máximo 3 líneas por respuesta');

  if (!prompt.includes('No escalar') && !prompt.includes('NO escalar'))
    errores.push('FALTA: regla de cuándo NO escalar');
if (!prompt.includes('REGLA 0') && !prompt.includes('output limpio') && !prompt.includes('etiquetas internas'))
  errores.push('FALTA regla de output limpio sin etiquetas internas');

  // ── RESULTADO ──
  return [{
    json: {
      prompt,
      aprobado: errores.length === 0,
      errores,
      errores_count: errores.length,
      chars: prompt.length
    }
  }];

