const prompt = $('Agente 2 - Prompt Orquestador').first().json.output ?? '';
const errores = [];
const input = $('Webhook omghat1').first().json.body;

// ── REGLAS ESENCIALES (solo las críticas) ──
if (!prompt.includes('qdrant_knowledge'))
  errores.push('FALTA: referencia a qdrant_knowledge');

if (!prompt.includes('[ESCALAR]'))
  errores.push('FALTA: instrucción [ESCALAR]');

if (!prompt.includes('[IMG:') && (input.images || []).length > 0)
  errores.push('FALTA: regla de etiqueta [IMG:url]');

if (!prompt.includes('[DOC:') && (input.catalogs || []).length > 0)
  errores.push('FALTA: regla de etiqueta [DOC:url|nombre]');

if (input.agent_name && !prompt.toLowerCase().includes(input.agent_name.toLowerCase()))
  errores.push(`FALTA: nombre del agente "${input.agent_name}"`);

if (input.escalation_phone && !prompt.includes(input.escalation_phone))
  errores.push('FALTA: teléfono de escalamiento');

if (prompt.includes('**') || prompt.includes('## ') || prompt.includes('```'))
  errores.push('CONTIENE: markdown prohibido');

if (prompt.length > 1200)
  errores.push(`EXCEDE: límite de caracteres (${prompt.length}/1200)`);

if (prompt.length < 200)
  errores.push(`MUY CORTO: (${prompt.length} chars)`);

// Verificar regla de output limpio
if (!prompt.includes('REGLA 0') && !prompt.toLowerCase().includes('output limpio') && !prompt.toLowerCase().includes('etiquetas internas'))
  errores.push('FALTA: regla de output limpio');

// Verificar brevedad
if (!prompt.includes('3 líneas') && !prompt.includes('máximo 3') && !prompt.includes('3 lineas'))
  errores.push('FALTA: regla de brevedad (máximo 3 líneas)');

return [{
  json: {
    prompt,
    aprobado: errores.length === 0,
    errores,
    errores_count: errores.length,
    chars: prompt.length
  }
}];

const slug = $('Webhook omghat1').item.json.body.agent_slug;
const promptFinal = $('Merge1').first().json.prompt_final || '';
const qdrantCheck = $('Verificar Qdrant').first().json;
const qdrantPoints = qdrantCheck.result?.points?.length ?? 0;

return [{
